const xlsxB64 = $json.stdout.trim();
const emailTo = $('Config').first().json['EMAIL_TO'];
const emailFrom = $('Config').first().json['EMAIL_FROM'];
const now = new Date().toISOString().substring(0, 10);
const po = $('Fetch Inactive Users').first().json.stdout || '';
const total = (po.match(/TOTAL_INACTIVE: (\d+)/) || [])[1] || '?';
const nc = (po.match(/NEVER_LOGIN: (\d+)/) || [])[1] || '?';
const oc = (po.match(/OLD_LOGIN: (\d+)/) || [])[1] || '?';
const subject = 'Usuarios inactivos (+90 días) - Reporte ' + now;
const html = '<html><body style="font-family:Arial,sans-serif;font-size:14px;color:#333">'
  + '<h2 style="color:#2F5496">Reporte de usuarios inactivos en Azure AD</h2>'
  + '<p>Se adjunta el listado de usuarios habilitados en Azure AD que <b>no han iniciado sesión</b> o cuyo <b>último login supera los 90 días</b>.</p>'
  + '<table style="border-collapse:collapse;margin:16px 0">'
  + '<tr><td style="padding:4px 12px;font-weight:bold">Total usuarios inactivos:</td><td>' + total + '</td></tr>'
  + '<tr><td style="padding:4px 12px;font-weight:bold">Sin login nunca:</td><td>' + nc + '</td></tr>'
  + '<tr><td style="padding:4px 12px;font-weight:bold">Último login &gt; 90 días:</td><td>' + oc + '</td></tr>'
  + '</table>'
  + '<p><b>Campos del reporte:</b></p>'
  + '<ul><li>UserPrincipalName</li><li>Last Login</li><li>Fecha Creación</li><li>Departamento</li></ul>'
  + '<p>Fecha: <b>' + now + '</b></p>'
  + '<p style="font-size:12px;color:#999;margin-top:24px">Generado automáticamente por n8n.</p>'
  + '</body></html>';
const fileName = 'Usuarios_Inactivos_90d_' + now + '.xlsx';
return [{
  json: { subject, html, emailTo, emailFrom, fileName },
  binary: {
    attachment: {
      data: xlsxB64,
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      fileName: fileName
    }
  }
}];
